import React from "react";

function About() {
  return (
    <>
      <main className="container">
        <h1 className="text-center p-5">About Me</h1>
        <div className="row p-5">
          <div className="col-md-6">
              <img
                src="/assets/profilemain.jpg"
                alt="Profile Image"
                style={{
                  width: "40%",
                  height: "auto",
                  borderRadius: "100%",
                  display: "block",
                  margin: "0 auto",
                }}
              />
          </div>
          <div className="col-md-6">
            <p>
              
            </p>
          </div>
        </div>
      </main>
    </>
  );
}

export default About;
